class Solution {
public:
    int findMinArrowShots(vector<vector<int>>& p) {
        sort(p.begin(), p.end(), [](auto& a, auto& b){ return a[1] < b[1]; });
        long long end=LLONG_MIN; int ans=0;
        for(auto& v:p) if(v[0]>end){ ans++; end=v[1]; }
        return ans;
    }
};

