int cmp452(const void* a, const void* b){ return (*(int**)a)[1]-(*(int**)b)[1]; }
int findMinArrowShots(int** points, int n, int* cs){
    qsort(points,n,sizeof(int*),cmp452);
    long long end=LLONG_MIN; int ans=0;
    for(int i=0;i<n;i++) if(points[i][0]>end){ ans++; end=points[i][1]; }
